import React, { createContext, useContext, useReducer } from 'react';
import { MOCK_RIDE_HISTORY } from '../data/mockData';

const AppContext = createContext();

const initialState = {
  // Booking
  pickup:       '',
  dropoff:      '',
  pickupCoords: null,
  dropoffCoords:null,
  selectedCab:  'mini',
  paymentMethod:'cash',
  promoCode:    '',
  promoApplied: false,
  promoDiscount:0,

  // Booking flow: idle | searching | found | riding | completed
  bookingStatus: 'idle',
  assignedDriver: null,
  rideProgress: 0,

  // History
  rideHistory: MOCK_RIDE_HISTORY,

  // User
  user: {
    name: 'Ashu Sharan',
    phone: '+91 72958 67927',
    initials: 'AS',
    walletBalance: 100,
    memberSince: 'March 2026',
    totalRides: 5,
    totalSpent: 9500,
  },

  // UI
  activeNav: 'book',
  notification: null,
};

function reducer(state, action) {
  switch (action.type) {
    case 'SET_PICKUP':
      return typeof action.payload === 'string'
        ? { ...state, pickup: action.payload, pickupCoords: null }
        : { ...state, pickup: action.payload.address, pickupCoords: action.payload.coords };
    case 'SET_DROPOFF':
      return typeof action.payload === 'string'
        ? { ...state, dropoff: action.payload, dropoffCoords: null }
        : { ...state, dropoff: action.payload.address, dropoffCoords: action.payload.coords };
    case 'SET_CAB':
      return { ...state, selectedCab: action.payload };
    case 'SET_PAYMENT':
      return { ...state, paymentMethod: action.payload };
    case 'APPLY_PROMO':
      return { ...state, promoCode: action.payload.code, promoApplied: true, promoDiscount: action.payload.discount };
    case 'CLEAR_PROMO':
      return { ...state, promoCode: '', promoApplied: false, promoDiscount: 0 };
    case 'SET_BOOKING_STATUS':
      return { ...state, bookingStatus: action.payload };
    case 'ASSIGN_DRIVER':
      return { ...state, assignedDriver: action.payload, bookingStatus: 'found' };
    case 'ADD_RIDE':
      return { ...state, rideHistory: [action.payload, ...state.rideHistory] };
    case 'SET_RIDE_PROGRESS':
      return { ...state, rideProgress: action.payload };
    case 'COMPLETE_RIDE':
      return {
        ...state,
        bookingStatus: 'completed',
        rideHistory: [action.payload, ...state.rideHistory],
        user: {
          ...state.user,
          totalRides: state.user.totalRides + 1,
          totalSpent: state.user.totalSpent + action.payload.amount,
        },
      };
    case 'CANCEL_RIDE':
      return { ...state, bookingStatus: 'idle', assignedDriver: null, rideProgress: 0 };
    case 'RESET_BOOKING':
      return { ...state, bookingStatus: 'idle', assignedDriver: null, rideProgress: 0, promoApplied: false, promoDiscount: 0, promoCode: '' };
    case 'SET_NAV':
      return { ...state, activeNav: action.payload };
    case 'SHOW_NOTIFICATION':
      return { ...state, notification: action.payload };
    case 'CLEAR_NOTIFICATION':
      return { ...state, notification: null };
    case 'UPDATE_WALLET':
      return { ...state, user: { ...state.user, walletBalance: state.user.walletBalance + action.payload } };
    default:
      return state;
  }
}

export function AppProvider({ children }) {
  const [state, dispatch] = useReducer(reducer, initialState);
  return (
    <AppContext.Provider value={{ state, dispatch }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  return useContext(AppContext);
}
